@@ -1282,9 +1282,9 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   const APInt *Offset1 = nullptr, *Offset2 = nullptr;
   if (V1 != V2) {
     Value *X;
-    if (match(V1, m_Add(m_Value(X), m_APInt(Offset1))))
+    if (match(V1, m_c_Add(m_Value(X), m_APInt(Offset1))))
       V1 = X;
-    if (match(V2, m_Add(m_Value(X), m_APInt(Offset2))))
+    if (match(V2, m_c_Add(m_Value(X), m_APInt(Offset2))))
       V2 = X;
   }

@@ -1293,13 +1293,21 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,

   ConstantRange CR1 = ConstantRange::makeExactICmpRegion(
       IsAnd ? ICmpInst::getInversePredicate(Pred1) : Pred1, *C1);
-  if (Offset1)
+  if (Offset1) {
     CR1 = CR1.subtract(*Offset1);
+    if (Pred1 == ICmpInst::ICMP_NE)
+      CR1 = CR1.intersectWith(ConstantRange(APInt::getMinValue(C1->getBitWidth()),
+                                            APInt::getMaxValue(C1->getBitWidth())));
+  }

   ConstantRange CR2 = ConstantRange::makeExactICmpRegion(
       IsAnd ? ICmpInst::getInversePredicate(Pred2) : Pred2, *C2);
-  if (Offset2)
+  if (Offset2) {
     CR2 = CR2.subtract(*Offset2);
+    if (Pred2 == ICmpInst::ICMP_NE)
+      CR2 = CR2.intersectWith(ConstantRange(APInt::getMinValue(C2->getBitWidth()),
+                                            APInt::getMaxValue(C2->getBitWidth())));
+  }

   Type *Ty = V1->getType();
   Value *NewV = V1;

